class URL {
    String protocol;
    String host;
    String path;

    public URL(String url) {
        int protocolEnd = url.indexOf("://");
        this.protocol = url.substring(0, protocolEnd);

        String rest = url.substring(protocolEnd + 3);
        int pathStart = rest.indexOf("/");

        if (pathStart == -1) {
            this.host = rest;
            this.path = "/";
        } else {
            this.host = rest.substring(0, pathStart);
            this.path = rest.substring(pathStart);
        }
    }
}

public class App {
    public static void main(String[] args) {
        URL u1 = new URL("https://google.com/search");
        URL u2 = new URL("http://example.com");

        System.out.println("Protocol: " + u1.protocol + " | Host: " + u1.host + " | Path: " + u1.path);
        System.out.println("Protocol: " + u2.protocol + " | Host: " + u2.host + " | Path: " + u2.path);
    }
}

class Point {
    double x;
    double y;

    public Point(double x, double y) {
        this.x = x;
        this.y = y;
    }

    public Point() {
        this(0, 0);
    }

    public Point(Point other) {
        this(other.x, other.y);
    }

    double distanceFrom(Point other) {
        double dx = this.x - other.x;
        double dy = this.y - other.y;
        return Math.sqrt(dx * dx + dy * dy);
    }
}

public class App {
    public static void main(String[] args) {
        Point p1 = new Point(3, 4);
        Point p2 = new Point();
        Point p3 = new Point(p1);

        System.out.println("P1: (" + p1.x + ", " + p1.y + ")");
        System.out.println("P2 (origin): (" + p2.x + ", " + p2.y + ")");
        System.out.println("P3 (copy of P1): (" + p3.x + ", " + p3.y + ")");
        System.out.println("Distance from P1 to origin: " + p1.distanceFrom(p2));
    }
}

class OrderItem {
    String productName;
    int quantity;
    double unitPrice;

    public OrderItem(String productName, int quantity, double unitPrice) {
        if (productName == null || productName.isBlank()) throw new IllegalArgumentException("Product name required");
        if (quantity <= 0) throw new IllegalArgumentException("Quantity must be positive");
        if (unitPrice < 0) throw new IllegalArgumentException("Unit price cannot be negative");

        this.productName = productName;
        this.quantity = quantity;
        this.unitPrice = unitPrice;
    }

    double lineTotal() {
        return quantity * unitPrice;
    }
}

class Order {
    int orderId;
    String customerName;
    OrderItem[] items;

    public Order(int orderId, String customerName, OrderItem[] items) {
        if (orderId <= 0) throw new IllegalArgumentException("Order ID must be positive");
        if (customerName == null || customerName.isBlank()) throw new IllegalArgumentException("Customer name required");
        if (items == null || items.length == 0) throw new IllegalArgumentException("Order must have at least one item");

        this.orderId = orderId;
        this.customerName = customerName;
        this.items = items;
    }

    double total() {
        double sum = 0;
        for (OrderItem item : items) {
            sum += item.lineTotal();
        }
        return sum;
    }
}

public class App {
    public static void main(String[] args) {
        OrderItem[] items = {
            new OrderItem("Mouse", 1, 599.0),
            new OrderItem("Keyboard", 1, 1499.0),
            new OrderItem("USB Hub", 2, 174.5)
        };

        Order order = new Order(1001, "Aisha", items);
        System.out.println("Order #" + order.orderId + " (" + order.customerName + ") total: ₹" + order.total());

        try {
            Order bad = new Order(1002, "Raj", new OrderItem[0]);
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
